Visualization 1: Water Demand Varies Sharply Across Cultivation Families

Show code# Order water levels
water_order &lt;- c("Very Low", "Low", "Medium", "High", "Very High")

# Compute proportions within each cultivation group
water_props &lt;- plants_filtered |&gt;
  filter(!is.na(water_clean)) |&gt;
  mutate(water_clean = factor(water_clean, levels = water_order)) |&gt;
  count(cultivation_clean, water_clean, .drop = FALSE) |&gt;
  group_by(cultivation_clean) |&gt;
  mutate(
    total = sum(n),
    pct = n / total
  ) |&gt;
  ungroup()

# Order cultivation groups by median water score
cult_order &lt;- plants_filtered |&gt;
  filter(!is.na(water_score)) |&gt;
  group_by(cultivation_clean) |&gt;
  summarise(med_water = median(water_score, na.rm = TRUE)) |&gt;
  arrange(med_water) |&gt;
  pull(cultivation_clean)

water_props &lt;- water_props |&gt;
  mutate(cultivation_clean = factor(cultivation_clean, levels = cult_order))

ggplot(water_props, aes(x = cultivation_clean, y = pct, fill = water_clean)) +
  geom_col(position = "fill", width = 0.75, color = "white", linewidth = 0.3) +
  scale_y_continuous(labels = percent_format(), expand = expansion(mult = c(0, 0.02))) +
  scale_fill_manual(
    values = c(
      "Very Low" = "#fef0d9",
      "Low"      = "#fdcc8a",
      "Medium"   = "#fc8d59",
      "High"     = "#e34a33",
      "Very High" = "#b30000"
    ),
    name = "Water\nRequirement"
  ) +
  labs(
    title = "Cucurbits and Salad greens are the thirstiest plant families",
    subtitle = "Share of species at each water-requirement level, by cultivation group",
    x = NULL,
    y = "Share of species",
    caption = "Source: Edible Plant Database (GROW Observatory) · TidyTuesday 2026 Wk 5 · Zhijun He · 2026-02-11"
  ) +
  theme_minimal(base_size = 13) +
  theme(
    plot.title = element_text(face = "bold", size = 14),
    plot.subtitle = element_text(color = "grey40", size = 11),
    plot.caption = element_text(color = "grey50", size = 8, hjust = 0),
    axis.text.x = element_text(angle = 30, hjust = 1),
    legend.position = "right",
    panel.grid.major.x = element_blank()
  )







Cucurbits (squash, melons, cucumbers) and Salad greens stand out: every Salad species requires at least “High” water, and a majority of Cucurbits do as well. Lamiaceae (herbs like basil, mint, oregano) and Chenopodiaceae (spinach, chard) cluster almost entirely at “Medium” or “Low,” making them far more forgiving in dry conditions. For a gardener in a drought-prone area, this chart suggests prioritizing herbs and leafy greens over melons and cucumbers.

Data Preparation

Show code# Join birds with ship records to carry along date and location.
bird_ship &lt;- birds |&gt;
  filter(!is.na(species_common_name)) |&gt;
  left_join(ships |&gt; select(record_id, date, latitude, longitude, activity),
            by = "record_id")

# The logbook frequently records identification at genus level
# (e.g. "Royal albatross sensu lato") or with plumage/age tags (AD, JUV).
# Collapse to a simpler species label by stripping trailing age/sex tokens
# and pooling obvious aggregates.
bird_ship &lt;- bird_ship |&gt;
  mutate(
    species_label = species_common_name |&gt;
      str_remove_all(" sensu lato") |&gt;
      str_remove_all("\\s+(AD|JUV|IMM|SUBAD|M|F)$") |&gt;
      str_trim(),
    species_label = fct_lump_min(species_label, min = 300)
  )

# Pick the most commonly recorded species (top 14) for the heatmap
top_species &lt;- bird_ship |&gt;
  filter(species_label != "Other") |&gt;
  count(species_label, sort = TRUE) |&gt;
  slice_head(n = 14) |&gt;
  pull(species_label)

beh_df &lt;- bird_ship |&gt;
  filter(species_label %in% top_species) |&gt;
  mutate(species_label = factor(species_label, levels = rev(top_species)))

