Exercise — Temperature Converter

Codeconvert_temp &lt;- function(temp, unit) {
    unit &lt;- toupper(unit)                       # tolerate "c" / "f"
    if (unit == "F") {
        (temp - 32) * 5/9                       # F → C
    } else if (unit == "C") {
        (temp * 9/5) + 32                       # C → F
    } else {
        stop("`unit` must be 'C' or 'F' (case-insensitive); got: ", unit)
    }
}

convert_temp(0,   unit = "C")   # 0°C   →  32°F

[1] 32

Codeconvert_temp(32,  unit = "F")   # 32°F  →   0°C

[1] 0

Codeconvert_temp(100, unit = "C")   # 100°C → 212°F

[1] 212

Codeconvert_temp(-40, unit = "F")   # −40°F → −40°C  (the fixed point)

[1] -40

Codeconvert_temp(98.6, unit = "f")  # lower-case tolerated

[1] 37


Three small choices worth naming:


Argument semantics. unit means “the unit the input temperature is in” — so unit = "F" triggers the F → C formula. This is a documentation decision, not an algorithmic one, and it’s where convert-temp functions most often confuse users.

Input tolerance. toupper() lets "c" and "f" work; this is cheap and removes a common point of frustration.

Explicit error on invalid unit. Without the else stop(), the function silently returns NULL for unit = "K". Silent NULL returns are a classic source of downstream bugs; failing loudly is better.

Benchmark — Four Ways to Build a Vector

Coderesults_nostorage &lt;- bench::mark(
    no_storage = {
        x &lt;- integer()
        for (i in seq_len(1e4)) x &lt;- c(x, i)
        x
    },
    iterations = 5
)

results_storage &lt;- bench::mark(
    with_storage = {
        x &lt;- vector("integer", length = 1e4)
        for (i in seq_len(1e4)) x[i] &lt;- i
        x
    },
    iterations = 5
)

results_purrr &lt;- bench::mark(
    purrr_map = map_int(seq_len(1e4), ~ .x),
    iterations = 5
)

results_vectorized &lt;- bench::mark(
    vectorized = seq_len(1e4),
    iterations = 5
)

bind_rows(results_nostorage, results_storage, results_purrr, results_vectorized) |&gt;
    mutate(type = c("for_loop_no_storage", "for_loop_with_storage",
                    "purrr_map_int", "vectorized_seq_len")) |&gt;
    select(type, median, mem_alloc, n_gc)

# A tibble: 4 × 3
  type                    median mem_alloc
  &lt;chr&gt;                 &lt;bch:tm&gt; &lt;bch:byt&gt;
1 for_loop_no_storage    79.22ms   191.2MB
2 for_loop_with_storage 847.14µs    48.8KB
3 purrr_map_int           4.67ms      46KB
4 vectorized_seq_len     81.96ns        0B


Reading across: vectorized_seq_len is the fastest and allocates the least memory; for_loop_with_storage is in the same ballpark as purrr_map_int; for_loop_no_storage is roughly two orders of magnitude slower and allocates dramatically more memory because every c(x, i) copies the entire growing vector. The n_gc (garbage-collection) column tells the same story from the memory-pressure side.
Conceptual point. purrr::map_*() is not faster than a pre-allocated for loop — both are running roughly the same work under the hood. What purrr buys you is not speed but readability and type safety: map_int fails loudly if any element isn’t an integer, whereas an unchecked loop can silently produce garbage.

pmap() — Multi-Argument Iteration
Two small str_sub() examples

Code# Example 1: vary string, start, and end simultaneously
varying_all &lt;- tibble(
    string = c("apple", "banana", "cherry"),
    start  = c(1, 2, 4),
    end    = c(2, 3, 5)
)

pmap_chr(varying_all, str_sub)

[1] "ap" "an" "rr"



Code# Example 2: vary start and end, hold string constant
varying_positions &lt;- tibble(
    start = c(1, 2, 4),
    end   = c(2, 3, 5)
)

pmap_chr(varying_positions, str_sub, string = "abcde")

[1] "ab" "bc" "de"


Two design points from these:


pmap matches tibble column names to function argument names. The column names in varying_all match str_sub’s argument names (string, start, end) exactly, which is why it works.
Arguments that should be held constant across iterations are passed as extra named arguments after the function. In Example 2, string = "abcde" is fixed; only start and end vary.

pmap() case study — many model specifications on diamonds

This is the ICA 11 case study redone with pmap, avoiding the explicit for loop. I’m also carrying over two fixes from ICA 11: the parameter drop_outliers rather than remove_outliers (to avoid shadowing the function of the same name), and abs(.zscore) &lt;= sd_thresh for a symmetric outlier definition.

Code# Helper: remove outliers on `what_var` beyond sd_thresh SDs from the mean
remove_outliers &lt;- function(data, what_var, sd_thresh) {
    data |&gt;
        mutate(
            .zscore = ({{ what_var }} - mean({{ what_var }}, na.rm = TRUE)) /
                       sd({{ what_var }}, na.rm = TRUE)
        ) |&gt;
        filter(abs(.zscore) &lt;= sd_thresh) |&gt;
        select(-.zscore)
}

# Dispatcher: outer parameter renamed to `drop_outliers` to avoid name collision
fit_model &lt;- function(data, mod_formula, drop_outliers) {
    if (drop_outliers) {
        data &lt;- remove_outliers(data, what_var = carat, sd_thresh = 3)
    }
    lm(as.formula(mod_formula), data = data)
}


Build the argument grid. The template builds nested formulas via map_chr() — I keep that pattern because it generalises to an arbitrary predictor list:

Codexs &lt;- diamonds |&gt; select(carat, cut, clarity, color) |&gt; names()

df_arg_combos &lt;- crossing(
    mod_formula = str_c(
        "price ~ ",
        map_chr(seq_along(xs), ~ str_c(xs[1:.x], collapse = " + "))
    ),
    drop_outliers = c(TRUE, FALSE)
)

df_arg_combos

# A tibble: 8 × 2
  mod_formula                           drop_outliers
  &lt;chr&gt;                                 &lt;lgl&gt;        
1 price ~ carat                         FALSE        
2 price ~ carat                         TRUE         
3 price ~ carat + cut                   FALSE        
4 price ~ carat + cut                   TRUE         
5 price ~ carat + cut + clarity         FALSE        
6 price ~ carat + cut + clarity         TRUE         
7 price ~ carat + cut + clarity + color FALSE        
8 price ~ carat + cut + clarity + color TRUE         


Now fit all eight specifications in one pmap() call, storing the results in a list-column alongside the configuration that produced them:

Codefitted &lt;- df_arg_combos |&gt;
    mutate(
        mod = pmap(
            list(mod_formula = mod_formula, drop_outliers = drop_outliers),
            fit_model,
            data = diamonds
        )
    )

fitted

# A tibble: 8 × 3
  mod_formula                           drop_outliers mod   
  &lt;chr&gt;                                 &lt;lgl&gt;         &lt;list&gt;
1 price ~ carat                         FALSE         &lt;lm&gt;  
2 price ~ carat                         TRUE          &lt;lm&gt;  
3 price ~ carat + cut                   FALSE         &lt;lm&gt;  
4 price ~ carat + cut                   TRUE          &lt;lm&gt;  
5 price ~ carat + cut + clarity         FALSE         &lt;lm&gt;  
6 price ~ carat + cut + clarity         TRUE          &lt;lm&gt;  
7 price ~ carat + cut + clarity + color FALSE         &lt;lm&gt;  
8 price ~ carat + cut + clarity + color TRUE          &lt;lm&gt;  


The list(mod_formula = ..., drop_outliers = ...) inside pmap() is explicit about which columns feed which arguments — safer than relying on column-name-to-argument-name matching when the tibble has additional columns you don’t want passed. data = diamonds is the fixed argument carried through every iteration.
Extract a tidy comparison table
A list-column of lm objects isn’t useful until we pull out comparable statistics:

Codefitted |&gt;
    mutate(
        n_used        = map_int(mod, ~ length(residuals(.x))),
        r_squared     = map_dbl(mod, ~ summary(.x)$r.squared),
        adj_r_squared = map_dbl(mod, ~ summary(.x)$adj.r.squared),
